import React, { useState, useEffect } from "react";
import { Link } from "react-router-dom";
import axios from "axios";

const Navbar = () => {
  const [showDropdown, setShowDropdown] = useState(false);
  const [categories, setCategories] = useState([]);
  const [loading, setLoading] = useState(true);

  const API_BASE_URL = "http://localhost:5000/api";

  useEffect(() => {
    fetchCategories();
  }, []);

  const fetchCategories = async () => {
    try {
      const res = await axios.get(`${API_BASE_URL}/categories`);
      setCategories(res.data || []);
      setLoading(false);
    } catch (err) {
      console.error("Lỗi tải danh mục:", err);
      setLoading(false);
    }
  };

  return (
    <nav className="bg-primary text-white shadow-soft">
      <div className="max-w-7xl mx-auto flex items-center justify-between px-6 py-3">
        {/* Logo */}
        <Link to="/" className="flex items-center gap-2">
          <img
            src="/logo.png"
            alt="DDT Flower"
            className="w-12 h-12 object-contain rounded-full border border-accent"
          />
          <h1 className="text-2xl font-bold tracking-wide">DDT Flower</h1>
        </Link>

        {/* Menu Links */}
        <div className="hidden md:flex gap-8 font-medium">
          <Link to="/" className="hover:text-accent transition-colors">
            Trang chủ
          </Link>
          <Link to="/product" className="hover:text-accent transition-colors">
            Sản phẩm
          </Link>
          <Link to="/about" className="hover:text-accent transition-colors">
            Giới thiệu
          </Link>
          <Link to="/contact" className="hover:text-accent transition-colors">
            Liên hệ
          </Link>
        </div>

        {/* Dropdown danh mục */}
        <div className="relative">
          <button
            onClick={() => setShowDropdown(!showDropdown)}
            className="bg-light text-primary font-semibold px-4 py-2 rounded shadow hover:bg-secondary transition"
          >
            ☰ Danh mục
          </button>

          {showDropdown && (
            <div className="absolute top-full left-0 mt-2 bg-white border border-accent rounded-lg shadow-lg w-64 z-50">
              {loading ? (
                <p className="text-center py-3 text-accent text-sm">
                  Đang tải...
                </p>
              ) : (
                <ul className="max-h-80 overflow-y-auto">
                  {categories.map((c) => (
                    <li
                      key={c._id}
                      className="px-4 py-3 border-b border-secondary hover:bg-secondary hover:text-primary transition"
                    >
                      <Link
                        to={`/category/${c.slug}`}
                        onClick={() => setShowDropdown(false)}
                        className="block w-full"
                      >
                        {c.name}
                      </Link>
                    </li>
                  ))}
                </ul>
              )}
            </div>
          )}
        </div>
      </div>
    </nav>
  );
};

export default Navbar;
